import { useState, useEffect } from 'react';

function Chronometre() {
  const [temps, setTemps] = useState(0); // temps en centièmes de seconde
  const [actif, setActif] = useState(false);

  useEffect(() => {
    let interval = null;
    if (actif) {
      interval = setInterval(() => {
        setTemps(prev => prev + 1);
      }, 10); // 10ms = 1 centième
    } else if (!actif && temps !== 0) {
      clearInterval(interval);
    }
    return () => clearInterval(interval);
  }, [actif]);

  const demarrer = () => setActif(true);
  const pause = () => setActif(false);
  const reset = () => {
    setActif(false);
    setTemps(0);
  };

  const minutes = Math.floor(temps / 6000);
  const secondes = Math.floor((temps % 6000) / 100);
  const centiemes = temps % 100;

  return (
    &lt;div&gt;
      &lt;div className="affichage"&gt;
        {String(minutes).padStart(2, '0')}:
        {String(secondes).padStart(2, '0')}:
        {String(centiemes).padStart(2, '0')}
      &lt;/div&gt;
      &lt;button onClick={demarrer} disabled={actif}&gt;Démarrer&lt;/button&gt;
      &lt;button onClick={pause} disabled={!actif}&gt;Pause&lt;/button&gt;
      &lt;button onClick={reset}&gt;Réinitialiser&lt;/button&gt;
    &lt;/div&gt;
  );
}

export default Chronometre;
