import { useState, useEffect } from 'react';
import io from 'socket.io-client';

function NotificationBoard({ serveurUrl }) {
  const [notifications, setNotifications] = useState([]);
  const [connecte, setConnecte] = useState(false);
  const [erreur, setErreur] = useState(null);

  useEffect(() => {
    let socket = null;
    let estMonte = true;

    const connecter = () => {
      try {
        socket = io(serveurUrl, {
          transports: ['websocket'],
          reconnectionAttempts: 3
        });

        socket.on('connect', () => {
          if (estMonte) {
            setConnecte(true);
            setErreur(null);
          }
        });

        socket.on('disconnect', () => {
          if (estMonte) setConnecte(false);
        });

        socket.on('connect_error', (err) => {
          if (estMonte) {
            setErreur(`Erreur de connexion : ${err.message}`);
            setConnecte(false);
          }
        });

        socket.on('nouvelle_notification', (data) => {
          if (estMonte) {
            setNotifications(prev => [
              { id: Date.now(), ...data, timestamp: new Date() },
              ...prev
            ]);
          }
        });

      } catch (err) {
        if (estMonte) setErreur(err.message);
      }
    };

    connecter();

    // Fonction de nettoyage
    return () => {
      estMonte = false;
      if (socket) {
        socket.disconnect();
        socket.close();
      }
    };
  }, [serveurUrl]); // Se réexécute si l'URL change

  if (erreur) return &lt;div className="error"&gt;⚠️ {erreur}&lt;/div&gt;;
  if (!connecte) return &lt;div&gt;Connexion en cours...&lt;/div&gt;;

  return (
    &lt;div className="notifications"&gt;
      &lt;h3&gt;Notifications en temps réel ({notifications.length})&lt;/h3&gt;
      {notifications.length === 0 && &lt;p&gt;Aucune notification pour l'instant&lt;/p&gt;}
      &lt;ul&gt;
        {notifications.map(notif => (
          &lt;li key={notif.id}&gt;
            &lt;strong&gt;{notif.timestamp.toLocaleTimeString()}&lt;/strong&gt; : {notif.message}
          &lt;/li&gt;
        ))}
      &lt;/ul&gt;
    &lt;/div&gt;
  );
}

export default NotificationBoard;
