import { useState, useEffect, useRef } from 'react';

function AutoSaveEditor({ documentId, sauvegarder }) {
  const [texte, setTexte] = useState('');
  const [dernierSauvegarde, setDernierSauvegarde] = useState(null);
  const [sauvegardeEnCours, setSauvegardeEnCours] = useState(false);
  const texteRef = useRef(texte);

  // Garder une référence à jour du texte pour la cleanup
  useEffect(() => {
    texteRef.current = texte;
  }, [texte]);

  // Sauvegarde périodique toutes les 5 secondes si le contenu a changé
  useEffect(() => {
    let interval = null;

    const effectuerSauvegarde = async () => {
      if (sauvegardeEnCours) return;

      const texteActuel = texteRef.current;
      const textePrecedent = dernierSauvegarde;

      if (texteActuel !== textePrecedent && texteActuel.trim() !== '') {
        setSauvegardeEnCours(true);
        try {
          await sauvegarder({ id: documentId, contenu: texteActuel });
          setDernierSauvegarde(texteActuel);
          console.log('Sauvegarde auto effectuée');
        } catch (err) {
          console.error('Erreur sauvegarde:', err);
        } finally {
          setSauvegardeEnCours(false);
        }
      }
    };

    interval = setInterval(effectuerSauvegarde, 5000);

    return () => clearInterval(interval);
  }, [documentId, sauvegarder, dernierSauvegarde, sauvegardeEnCours]);

  // Sauvegarde au démontage
  useEffect(() => {
    return () => {
      const texteFinal = texteRef.current;
      if (texteFinal !== dernierSauvegarde && texteFinal.trim() !== '') {
        sauvegarder({ id: documentId, contenu: texteFinal }).catch(console.error);
      }
    };
  }, [documentId, sauvegarder, dernierSauvegarde]);

  return (
    &lt;div&gt;
      &lt;textarea
        value={texte}
        onChange={(e) => setTexte(e.target.value)}
        rows={20}
        cols={80}
        placeholder="Écrivez votre contenu ici..."
      /&gt;
      {sauvegardeEnCours && &lt;div className="status"&gt;💾 Sauvegarde en cours...&lt;/div&gt;}
      {dernierSauvegarde === texte && texte !== '' && (
        &lt;div className="status success"&gt;✓ Sauvegardé&lt;/div&gt;
      )}
    &lt;/div&gt;
  );
}

export default AutoSaveEditor;
